// Paso 1: Filtro de Imágenes - Evolution API / Baileys
const body = $input.first().json.body ?? $input.first().json;

// Tipos de mensaje que contienen imagen según el estándar Baileys
const IMAGE_TYPES = ['imageMessage', 'image'];

// --- Extracción del tipo de mensaje ---
const messageType =
  body?.data?.messageType ||
  body?.messageType ||
  body?.data?.message?.messageType ||
  null;

const message =
  body?.data?.message ||
  body?.message ||
  null;

// --- Filtro principal: solo imágenes ---
if (!messageType || !IMAGE_TYPES.includes(messageType)) {
  return []; // Detiene silenciosamente
}

// --- Extracción del remitente ---
const remoteJid =
  body?.data?.key?.remoteJid ||
  body?.key?.remoteJid ||
  body?.data?.remoteJid ||
  null;

if (!remoteJid) {
  return [];
}

// --- Extracción del número limpio ---
const phoneNumber = remoteJid.replace(/@s\.whatsapp\.net$/, '').replace(/@.*$/, '');

// --- Extracción del nombre ---
const pushName =
  body?.data?.pushName ||
  body?.pushName ||
  null;

// --- Extracción de la imagen ---
const imageBase64 =
  message?.imageMessage?.jpegThumbnail ||
  message?.base64 ||
  body?.data?.message?.base64 ||
  null;

const imageUrl =
  message?.imageMessage?.url ||
  body?.data?.mediaUrl ||
  body?.mediaUrl ||
  null;

const imageCaption =
  message?.imageMessage?.caption ||
  body?.data?.message?.imageMessage?.caption ||
  '';

// --- Validación ---
if (!imageBase64 && !imageUrl) {
  return [];
}

// --- Instancia de Evolution API ---
const instanceName =
  body?.instance ||
  body?.data?.instance ||
  'default';

// --- Output limpio ---
return [
  {
    json: {
      phoneNumber,
      remoteJid,
      pushName,
      instanceName,
      imageBase64: imageBase64 ?? null,
      imageUrl:   imageUrl   ?? null,
      imageCaption,
      messageType,
      receivedAt: new Date().toISOString(),
    }
  }
];

