// Paso 2b: Parsear y validar respuesta de Gemini
const geminiRaw =
  $input.first().json?.candidates?.[0]?.content?.parts?.[0]?.text || '';

// Limpieza defensiva
const cleaned = geminiRaw
  .replace(/```json/gi, '')
  .replace(/```/g, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Gemini devolvió JSON inválido: "${cleaned}"`);
}

// Validación de claves obligatorias
const requiredKeys = ['prenda', 'color', 'talla_detectada', 'precio_detectado'];
for (const key of requiredKeys) {
  if (!(key in parsed)) {
    throw new Error(`Clave faltante en respuesta de Gemini: "${key}"`);
  }
}

// Normalización
const result = {
  prenda:           String(parsed.prenda  || '').toLowerCase().trim(),
  color:            String(parsed.color   || '').toLowerCase().trim(),
  talla_detectada:  parsed.talla_detectada  ?? null,
  precio_detectado: parsed.precio_detectado != null
                      ? Number(parsed.precio_detectado)
                      : null,
  // Propagamos datos del Paso 1
  phoneNumber:   $('Filtro de Imágenes').first().json.phoneNumber,
  remoteJid:     $('Filtro de Imágenes').first().json.remoteJid,
  pushName:      $('Filtro de Imágenes').first().json.pushName,
  instanceName:  $('Filtro de Imágenes').first().json.instanceName,
  receivedAt:    $('Filtro de Imágenes').first().json.receivedAt,
};

return [{ json: result }];

// Paso 3: Evaluación de stock contra datos de Gemini

// --- Datos de Gemini ---
const gemini = $('Parsear Respuesta Gemini').first().json;

const prendaBuscada  = gemini.prenda;
const colorBuscado   = gemini.color;
const tallaBuscada   = gemini.talla_detectada;
const precioDetect   = gemini.precio_detectado;

// --- Resultados de Supabase ---
const productos = $input.all().map(item => item.json);

// CASO 1: Sin resultados
if (!productos || productos.length === 0) {
  return [{
    json: {
      hayStock:       false,
      motivoNoStock:  'prenda_no_encontrada',
      mensaje:        `No tenemos "${prendaBuscada}" registrada en el inventario.`,
      prendaBuscada,
      colorBuscado,
      tallaBuscada,
      precioDetect,
      matchProducto:  null,
      phoneNumber:    gemini.phoneNumber,
      remoteJid:      gemini.remoteJid,
      pushName:       gemini.pushName,
      instanceName:   gemini.instanceName,
    }
  }];
}

// HELPER: normaliza strings
const norm = (str) =>
  (str ?? '').toLowerCase().normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim();

// PASO A: Filtrado por color
let candidatos = productos.filter(p => p.activo !== false);

if (colorBuscado) {
  const porColorExacto = candidatos.filter(p => norm(p.color) === norm(colorBuscado));
  const porColorParcial = candidatos.filter(p =>
    norm(p.color).includes(norm(colorBuscado)) ||
    norm(colorBuscado).includes(norm(p.color))
  );
  candidatos = porColorExacto.length > 0
    ? porColorExacto
    : porColorParcial.length > 0
      ? porColorParcial
      : candidatos;
}

// PASO B: Evaluación de stock por talla
let matchProducto     = null;
let hayStock          = false;
let motivoNoStock     = null;
let stockDisponible   = null;
let tallasConStock    = [];

for (const producto of candidatos) {
  const stockPorTalla = producto.stock_por_talla ?? {};

  tallasConStock = Object.entries(stockPorTalla)
    .filter(([, unidades]) => Number(unidades) > 0)
    .map(([talla]) => talla);

  const hayAlgunStock = tallasConStock.length > 0;

  if (!hayAlgunStock) {
    motivoNoStock  = 'agotado_todas_tallas';
    matchProducto  = producto;
    continue;
  }

  if (tallaBuscada) {
    const tallaNorm  = norm(tallaBuscada);
    const stockTalla = Object.entries(stockPorTalla).find(
      ([talla]) => norm(talla) === tallaNorm
    );

    if (stockTalla && Number(stockTalla[1]) > 0) {
      hayStock        = true;
      motivoNoStock   = null;
      stockDisponible = Number(stockTalla[1]);
      matchProducto   = producto;
      break;
    } else {
      motivoNoStock = 'talla_agotada';
      matchProducto = producto;
    }
  } else {
    hayStock        = true;
    motivoNoStock   = null;
    stockDisponible = tallasConStock.reduce((sum, t) =>
      sum + Number(stockPorTalla[t]), 0
    );
    matchProducto   = producto;
    break;
  }
}

// PASO C: Mensaje de respuesta
let mensajeRespuesta;

if (hayStock && tallaBuscada) {
  mensajeRespuesta =
    `✅ ¡Tenemos tu ${matchProducto.prenda} ${matchProducto.color} en talla ${tallaBuscada}!\n` +
    `📦 Stock disponible: ${stockDisponible} unidad(es)\n` +
    `💰 Precio: $${matchProducto.precio_base?.toLocaleString('es-CO') ?? precioDetect ?? 'consultar'}`;
} else if (hayStock && !tallaBuscada) {
  mensajeRespuesta =
    `✅ Tenemos ${matchProducto.prenda} ${matchProducto.color} disponible.\n` +
    `📏 Tallas con stock: ${tallasConStock.join(', ')}\n` +
    `💰 Precio: $${matchProducto.precio_base?.toLocaleString('es-CO') ?? precioDetect ?? 'consultar'}\n` +
    `¿Cuál talla necesitas?`;
} else if (motivoNoStock === 'talla_agotada') {
  mensajeRespuesta =
    `😔 Lo sentimos, la talla *${tallaBuscada}* de la ${matchProducto.prenda} ${matchProducto.color} está agotada.\n` +
    `📏 Tallas disponibles: ${tallasConStock.join(', ') || 'ninguna por ahora'}`;
} else if (motivoNoStock === 'agotado_todas_tallas') {
  mensajeRespuesta =
    `😔 Tenemos la ${matchProducto?.prenda} ${matchProducto?.color} en catálogo, pero está agotada en todas las tallas.`;
} else {
  mensajeRespuesta =
    `🔍 No encontramos coincidencias para *${prendaBuscada}* ` +
    `${colorBuscado ? `en color *${colorBuscado}*` : ''} en nuestro inventario actual.`;
}

return [{
  json: {
    hayStock,
    motivoNoStock,
    mensajeRespuesta,
    stockDisponible,
    tallasConStock,
    tallaBuscada,
    colorBuscado,
    prendaBuscada,
    precioDetect,
    matchProducto,
    phoneNumber:   gemini.phoneNumber,
    remoteJid:     gemini.remoteJid,
    pushName:      gemini.pushName,
    instanceName:  gemini.instanceName,
  }
}];

// Paso 4: Construcción del mensaje de respuesta para WhatsApp

const data = $input.first().json;

const {
  hayStock,
  motivoNoStock,
  matchProducto,
  tallaBuscada,
  colorBuscado,
  prendaBuscada,
  tallasConStock,
  stockDisponible,
  precioDetect,
  pushName,
  remoteJid,
  instanceName,
  phoneNumber,
} = data;

// HELPER: formatea precio en pesos colombianos
const formatPrecio = (valor) => {
  if (valor == null) return null;
  return Number(valor).toLocaleString('es-CO', {
    style:    'currency',
    currency: 'COP',
    minimumFractionDigits: 0,
  });
};

// HELPER: capitaliza primera letra
function capitalize(str) {
  if (!str) return '';
  return str.charAt(0).toUpperCase() + str.slice(1);
}

const nombre = pushName ? `*${pushName.split(' ')[0]}*` : 'amig@';
const precioFinal = formatPrecio(matchProducto?.precio_base ?? precioDetect);

let textoMensaje;

if (hayStock) {
  if (tallaBuscada) {
    textoMensaje =
      `¡Hola, ${nombre}! 👋\n\n` +
      `✅ ¡Excelente elección! Tenemos disponible:\n\n` +
      `👕 *${capitalize(matchProducto.prenda)}* en color *${matchProducto.color}*\n` +
      `📏 Talla: *${tallaBuscada}*\n` +
      `📦 Unidades disponibles: *${stockDisponible}*\n` +
      (precioFinal ? `💰 Precio: *${precioFinal}*\n` : '') +
      `\n¿Te gustaría apartar una unidad? Escríbenos *SÍ* para continuar con tu pedido. 🛍️`;
  } else {
    const tallasTexto = tallasConStock.join(' | ');
    textoMensaje =
      `¡Hola, ${nombre}! 👋\n\n` +
      `✅ ¡Tenemos esta prenda disponible!\n\n` +
      `👕 *${capitalize(matchProducto.prenda)}* en color *${matchProducto.color}*\n` +
      `📏 Tallas con stock: *${tallasTexto}*\n` +
      (precioFinal ? `💰 Precio: *${precioFinal}*\n` : '') +
      `\n¿Cuál talla necesitas? Responde con la talla y la apartamos para ti. 😊`;
  }
} else {
  if (motivoNoStock === 'talla_agotada') {
    const tallasTexto = tallasConStock.length > 0 ? tallasConStock.join(' | ') : null;
    textoMensaje =
      `¡Hola, ${nombre}! 👋\n\n` +
      `😔 Lo sentimos mucho. La talla *${tallaBuscada}* de la ` +
      `*${capitalize(matchProducto.prenda)} ${matchProducto.color}* ` +
      `se encuentra agotada en este momento.\n\n` +
      (tallasTexto
        ? `📏 Aún tenemos disponibilidad en: *${tallasTexto}*\n\n¿Te interesa alguna de estas tallas? 😊`
        : `⏳ Estamos esperando reposición próximamente.\n\n¿Deseas que te avisemos cuando llegue tu talla? Escribe *AVISAR* y te notificamos.`);
  } else if (motivoNoStock === 'agotado_todas_tallas') {
    textoMensaje =
      `¡Hola, ${nombre}! 👋\n\n` +
      `😔 Qué pena informarte que la ` +
      `*${capitalize(matchProducto.prenda)} ${matchProducto.color}* ` +
      `está agotada en todas las tallas por el momento.\n\n` +
      `⏳ Esperamos reposición pronto.\n\n` +
      `¿Quieres que te notifiquemos cuando vuelva a estar disponible? Escribe *AVISAR* y te avisamos apenas llegue. 🔔`;
  } else {
    textoMensaje =
      `¡Hola, ${nombre}! 👋\n\n` +
      `🔍 Revisamos nuestro inventario y por el momento no contamos con ` +
      `*${prendaBuscada}*${colorBuscado ? ` en color *${colorBuscado}*` : ''} ` +
      `en nuestra colección actual.\n\n` +
      `📲 Si tienes otra prenda en mente, ¡envíanos la foto y la buscamos! ` +
      `También puedes escribirnos directamente para más información. 😊`;
  }
}

return [{
  json: {
    number:      remoteJid,
    text:        textoMensaje,
    instanceName,
    phoneNumber,
    remoteJid,
    hayStock,
    motivoNoStock: motivoNoStock ?? null,
  }
}];
